// LOINC code mapping for common Quest tests
const loincMapping = {
  '83036': { loinc: '4548-4', display: 'Hemoglobin A1c/Hemoglobin.total in Blood' },
  '2089-1': { loinc: '2089-1', display: 'LDL Cholesterol Direct' },
  '2085-9': { loinc: '2085-9', display: 'HDL Cholesterol' },
  '2093-3': { loinc: '2093-3', display: 'Cholesterol Total' },
  '2571-8': { loinc: '2571-8', display: 'Triglycerides' },
  '36916-5': { loinc: '36916-5', display: 'HIV 1+2 Ab+Ag' },
  '718-7': { loinc: '718-7', display: 'Hemoglobin' },
  '787-2': { loinc: '787-2', display: 'MCV' },
  '777-3': { loinc: '777-3', display: 'Platelet count' },
  '26464-8': { loinc: '26464-8', display: 'WBC count' },
  '789-8': { loinc: '789-8', display: 'RBC count' },
  '2345-7': { loinc: '2345-7', display: 'Glucose' },
  '2160-0': { loinc: '2160-0', display: 'Creatinine' },
  '3094-0': { loinc: '3094-0', display: 'BUN' },
  '17861-6': { loinc: '17861-6', display: 'Calcium' },
  '2951-2': { loinc: '2951-2', display: 'Sodium' },
  '2823-3': { loinc: '2823-3', display: 'Potassium' },
  '2075-0': { loinc: '2075-0', display: 'Chloride' },
  '1920-8': { loinc: '1920-8', display: 'AST' },
  '1742-6': { loinc: '1742-6', display: 'ALT' }
};

const testCode = $input.item.json.TEST_CODE;
const mapping = loincMapping[testCode];

return {
  json: {
    ...$input.item.json,
    LOINC_CODE: mapping?.loinc || testCode,
    LOINC_DISPLAY: mapping?.display || $input.item.json.TEST_NAME
  }
};

const row = $input.item.json;

// Determine interpretation based on reference range
let interpretation = null;
if (row.REF_HIGH && row.REF_LOW) {
  const value = parseFloat(row.RESULT);
  const high = parseFloat(row.REF_HIGH);
  const low = parseFloat(row.REF_LOW);

  if (!isNaN(value)) {
    if (value > high) {
      interpretation = { code: 'H', display: 'High' };
    } else if (value < low) {
      interpretation = { code: 'L', display: 'Low' };
    } else {
      interpretation = { code: 'N', display: 'Normal' };
    }
  }
}

// Handle qualitative results (Positive/Negative)
let valueComponent = {};
const resultValue = row.RESULT;

if (['Positive', 'Negative', 'Reactive', 'Non-Reactive', 'Detected', 'Not Detected'].includes(resultValue)) {
  valueComponent = {
    valueString: resultValue
  };
} else if (!isNaN(parseFloat(resultValue))) {
  valueComponent = {
    valueQuantity: {
      value: parseFloat(resultValue),
      unit: row.UNIT || '',
      system: 'http://unitsofmeasure.org',
      code: row.UNIT || ''
    }
  };
} else {
  valueComponent = {
    valueString: resultValue
  };
}

// Build reference range if available
let referenceRange = [];
if (row.REF_LOW || row.REF_HIGH) {
  const range = {};
  if (row.REF_LOW) {
    range.low = { value: parseFloat(row.REF_LOW), unit: row.UNIT };
  }
  if (row.REF_HIGH) {
    range.high = { value: parseFloat(row.REF_HIGH), unit: row.UNIT };
  }
  referenceRange.push(range);
}

// Create unique observation ID
const observationId = `quest-${row.TEST_CODE}-${row.PATIENT_ID}-${row.RESULT_DATE.replace(/-/g, '')}`;

const observation = {
  resourceType: 'Observation',
  id: observationId,
  meta: {
    source: 'Quest Diagnostics via n8n',
    lastUpdated: new Date().toISOString()
  },
  identifier: [
    {
      system: 'http://quest.com/accession',
      value: `${row.PATIENT_ID}-${row.RESULT_DATE}-${row.TEST_CODE}`
    }
  ],
  status: row.STATUS === 'F' ? 'final' : 'preliminary',
  category: [
    {
      coding: [
        {
          system: 'http://terminology.hl7.org/CodeSystem/observation-category',
          code: 'laboratory',
          display: 'Laboratory'
        }
      ]
    }
  ],
  code: {
    coding: [
      {
        system: 'http://loinc.org',
        code: row.LOINC_CODE,
        display: row.LOINC_DISPLAY
      }
    ],
    text: row.TEST_NAME
  },
  subject: {
    reference: `Patient/${row.PATIENT_ID}`,
    display: `${row.FIRST_NAME} ${row.LAST_NAME}`
  },
  effectiveDateTime: row.RESULT_DATE,
  issued: new Date().toISOString(),
  ...valueComponent
};

// Add interpretation if determined
if (interpretation) {
  observation.interpretation = [
    {
      coding: [
        {
          system: 'http://terminology.hl7.org/CodeSystem/v3-ObservationInterpretation',
          code: interpretation.code,
          display: interpretation.display
        }
      ]
    }
  ];
}

// Add reference range if available
if (referenceRange.length > 0) {
  observation.referenceRange = referenceRange;
}

return { json: observation };

const observations = $input.all().map(item => item.json);

// Split into batches of 100 for API efficiency
const BATCH_SIZE = 100;
const batches = [];

for (let i = 0; i < observations.length; i += BATCH_SIZE) {
  const batchObservations = observations.slice(i, i + BATCH_SIZE);

  const bundle = {
    resourceType: 'Bundle',
    type: 'batch',
    timestamp: new Date().toISOString(),
    entry: batchObservations.map(obs => ({
      fullUrl: `urn:uuid:${obs.id}`,
      resource: obs,
      request: {
        method: 'PUT',
        url: `Observation/${obs.id}`
      }
    }))
  };

  batches.push({ json: bundle });
}

return batches;

const items = $input.all();
const successCount = items.length;

const logEntry = {
  timestamp: new Date().toISOString(),
  workflow: 'FQHC Quest Lab Import',
  status: 'SUCCESS',
  bundlesProcessed: successCount,
  message: `Successfully uploaded ${successCount} observation bundles to HDIM`
};

console.log(JSON.stringify(logEntry));

return [{ json: logEntry }];

const error = $input.first().json;

const errorLog = {
  timestamp: new Date().toISOString(),
  workflow: 'FQHC Quest Lab Import',
  status: 'ERROR',
  error: error.message || 'Unknown error',
  details: error
};

// This would be sent to error tracking/alerting system
console.error(JSON.stringify(errorLog));

// Return for downstream error handling
return [{ json: errorLog }];

